class Solution {
public:
    int magicalString(int n) {
        vector<int> s(3, 1);
        int i = 2, j = 1;
        while (s.back() < n) {
            int k = s[i];
            for (int l = 1; l <= k; l++) {
                s.push_back(j + 1);
            }
            j = s.back();
            i++;
        }
        return s[n];
    }
};
